'use strict';
const path = require('path');

const LIB = require('../lib/jibo-cai-utils');
const RandomUtils = LIB.RandomUtils;


describe('Test Utils', function() {
  this.timeout(5000);

  beforeEach( () => {}
    
  );

  describe("randomWeightedSample", function() {

    const testWeightedData = [
      { data: 0, weight: 1 },
      { data: 1, weight: 10 }
    ];

    const weirdTestWeightedData = [
      { data: 0, weight: -1 },
      { data: 1, weight: 1 }
    ];

    const evilTestWeightedData = [
      { data: 0, weight: 0 },
      { data: 1, weight: -1 }
    ];

    it("should have many more 1's than 0's compared to a uniformly random sample", function(done) {
      const N_TEST_ITERS = 100;
      let weightedSample1s = 0;
      let uniformSample1s = 0;

      for( let i = 0; i < N_TEST_ITERS; i++ ) {
        weightedSample1s += RandomUtils.weightedRandomSample(testWeightedData);
        uniformSample1s += testWeightedData[Math.floor(Math.random() * testWeightedData.length)].data;
      }
      
      assert.equal(weightedSample1s > uniformSample1s, true);
      done();
    });

    it("should have ONLY 1's and no 0's in the weighted sample", function(done) {
      const N_TEST_ITERS = 1000;
      let weightedSample1s = 0;

      for( let i = 0; i < N_TEST_ITERS; i++ ) {
        weightedSample1s += RandomUtils.weightedRandomSample(weirdTestWeightedData);
      }
      
      assert.equal(weightedSample1s, N_TEST_ITERS);
      done();
    });

    it("should return nothing if there is only zero weight or negative weight objects", function(done) {
      let weightedSampleResult = RandomUtils.weightedRandomSample(evilTestWeightedData);
      expect(weightedSampleResult).to.eql({});
      done();
    });

  });


});
